INSERT INTO public.photos VALUES (21689, 'Club de Tenis 1938', 'AHPZ. Estudio Coyne. Manuel Coyne. 1938. El châ”œâ”‚fer de un alto mando del ejâ”œÂ®rcito nacionalista en posiciâ”œâ”‚n de espera con faria, a la puerta del "Real Zaragoza Club de Tenis", mientras su superior termina el partido. Este Club estaba ubicado en el Paseo de la Mina, junto al colegio de los Corazonistas, a la altura de La Caridad. Al otro lado del Huerva estaba el "Gas", cuyo identitario depâ”œâ”‚sito se vislumbra borroso al fondo de la imagen.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64753400, -0.87774700, '0101000020E6100000063065E08016ECBF2786E464E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002472506.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002472506.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002472506/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21893, 'Hospital musulmâ”œÃ­n 1938', 'Imagen centrada en la parte superior del chaflâ”œÃ­n del inmueble del nâ”¬â•‘ 7 de la plaza de Castelar, redenominada de Josâ”œÂ® Antonio, proyectado en 1934 por Antonio Merlo Garcâ”œÂ¡a de Pruneda para acoger la Delegaciâ”œâ”‚n de Hacienda, y habilitado como hospital musulmâ”œÃ­n durante la guerra de 1936-39. Con motivo de la visita de diversas autoridades la vâ”œÂ¡spera del "glorioso alzamiento", enfermeras y algunos enfermos saludan brazo al aire, mientras ondean las banderas de la Espaâ”œâ–’a nacionalista, de FET y JONS, y la jalifiana del territorio colonial de Marruecos.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64792700, -0.87914200, '0101000020E6100000F1475167EE21ECBF03999D45EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49921560763.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49921560763.webp', 'https://www.flickr.com/photos/zaragozaantigua/49921560763/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21920, 'Plaza de Castelar 1938', 'Imagen capturada durante el recital de guitarra que Regino Sâ”œÃ­inz de la Maza ofreciâ”œâ”‚ de buena tarde en el Saloncillo de visitas del Hospital Musulmâ”œÃ­n, con presencia de su director, Joaquâ”œÂ¡n de Benito, el personal facultativo y auxiliar, las "seâ”œâ–’oritas enfermeras", asâ”œÂ¡ como los heridos y enfermos allâ”œÂ¡ hospitalizados. El reconocido guitarrero interpretâ”œâ”‚ fragmentos de "nuestra mâ”œâ•‘sica clâ”œÃ­sica, exquisita, magna e imperial del siglo XVI en tiempos de Carlos I y Felipe II"... compuesta por Isaac Albâ”œÂ®niz, Enrique Granados y Joaquâ”œÂ¡n Malats a finales del siglo XIX y comienzos del XX. Ademâ”œÃ­s de ser portavoz de aquella "gloriosa Espaâ”œâ–’a Imperial", era considerado tambiâ”œÂ®n "portavoz de la mâ”œâ•‘sica Imperial de la Espaâ”œâ–’a Una, Grande y Libre". Este recital fue seguido de otro en el Grupo Escolar Joaquâ”œÂ¡n Costa, tambiâ”œÂ®n para tropas heridas, ademâ”œÃ­s de un concierto benâ”œÂ®fico a favor del Auxilio Social que tuvo como escenario el Teatro Parisiana, ya que este intâ”œÂ®rprete "desinteresadamente se ha puesto a la disposiciâ”œâ”‚n del Caudillo para toda obra patriâ”œâ”‚tica".', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64792700, -0.87914200, '0101000020E6100000F1475167EE21ECBF03999D45EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54237675965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54237675965.webp', 'https://www.flickr.com/photos/zaragozaantigua/54237675965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22005, 'Jefatura del Aire 1941', 'Dibujo del proyecto de nuevo edificio para la Jefatura del Aire del ejâ”œÂ®rcito, por Lorenzo Monclâ”œâ•‘s, 1941. Se inaugurâ”œâ”‚ en 1949, en la calle Mefisto 2, notablemente modificado respecto al proyecto que se muestra. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64803600, -0.87938900, '0101000020E6100000E2C96E66F423ECBFB950F9D7F2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36756237876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36756237876.webp', 'https://www.flickr.com/photos/zaragozaantigua/36756237876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22098, 'P.â”¬â•‘ de la Mina 1951', 'Vista aâ”œÂ®rea del paseo de la Mina y y su entorno, hacia 1950. Abajo, el solar de los futuros bloques de la calle Concepciâ”œâ”‚n, propiedad de una mutualidad aseguradora, y el gasâ”œâ”‚geno. En el centro, el colegio Corazonistas y el Club de Tenis. Arriba a la derecha, la plaza de Josâ”œÂ® Antonio. Fuente: www.facebook.com/photo.php?fbid=519637008191327&set=p...', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64818900, -0.87708400, '0101000020E61000002009FB761211ECBF40506EDBF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20349410738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20349410738.webp', 'https://www.flickr.com/photos/zaragozaantigua/20349410738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22281, 'Quiosco de la Mâ”œâ•‘sica 1968', 'Andamios alrededor del Quiosco de la Mâ”œâ•‘sica en su ubicaciâ”œâ”‚n de la Plaza de los Sitios a finales del mes de enero, cuando se estaba procediendo a desmontarlo y trasladarlo despuâ”œÂ®s al Parque Primo de Rivera. Llevaba casi 44 aâ”œâ–’os en esa ubicaciâ”œâ”‚n (en su Segunda â”œÃ«poca). Fuente visual: Gerardo Sancho Ramo, en AMZ', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64840000, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15013034895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15013034895.webp', 'https://www.flickr.com/photos/zaragozaantigua/15013034895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22294, 'Huerva 1965', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 26/03/1965. "Niâ”œâ–’os jugando en la margen del Huerva." El râ”œÂ¡o Huerva a su paso por la ciudad, y en algunos de los tramos aâ”œâ•‘n al aire, presentaba importantes pendientes que hacâ”œÂ¡an complicado deambular por su ribera (calles Manuel Lasala, Alfâ”œÂ®rez Provisional, Coimbra...). El râ”œÂ¡o aparecâ”œÂ¡a "encajonado" de forma natural, aislâ”œÃ­ndolo de su entorno, salvo para los osados. En la imagen, algunos de los osados que encontraban en este lugar una prolongaciâ”œâ”‚n de las calles y caminos en que jugar y socializarse. Entorno de la calle Coimbra.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64807100, -0.87657800, '0101000020E61000002D944C4EED0CECBF363E93FDF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15391825761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15391825761.webp', 'https://www.flickr.com/photos/zaragozaantigua/15391825761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22333, 'Huerva 1968', 'Imagen de la brusca curva del Huerva en el paseo de la Mina, una captura un poco antes del cubrimiento de este tramo del cauce del râ”œÂ¡o, que llegarâ”œÃ­ justo hasta la pasarela de hierro. A la derecha quedan las antiguas instalaciones de la harinera de los Hermanos Solsona, funcional entre 1900 y 1922, que junto a la cercana de Marcos Samper conformaba uno de los nâ”œâ•‘cleos urbanos de este sector industrial de transformaciâ”œâ”‚n. Varias dâ”œÂ®cadas despuâ”œÂ®s, y tras su derribo, sobre ella serâ”œÃ­ construido el pâ”œâ•‘blico IES "Medina Albaida". Al fondo, el icâ”œâ”‚nico depâ”œâ”‚sito del "Gas" del Camino de las Torres, y los bloques de viviendas de la calle Coâ”œÂ¡mbra. La pasarela sobre el râ”œÂ¡o era denominada "de Corazonistas", pues conectaba directamente con el colegio que al otro lado del râ”œÂ¡o tenâ”œÂ¡an los Hermanos del Sagrado Corazâ”œâ”‚n desde finales de los aâ”œâ–’os 20. Tras el cubrimiento, la continua y tolerada invasiâ”œâ”‚n privada del Dominio Pâ”œâ•‘blico Hidrâ”œÃ­ulico en este sector del râ”œÂ¡o, hace que el Huerva siga siendo un extraâ”œâ–’o canal de agua, visible, pero lejano, como ajeno. Fuente visual: AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64636400, -0.87781100, '0101000020E6100000B53522180717ECBFE7A7380EBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19259677283.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19259677283.webp', 'https://www.flickr.com/photos/zaragozaantigua/19259677283/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25982, 'La Hâ”œÂ¡pica y El Huevo 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 27/07/1975. Imagen desde altura del estado de las cosas en la Romareda, en la zona cercana a la Hâ”œÂ¡pica (muros, â”œÃ­rboles, instalaciones deportivas varias, piscina...) Los camiones estâ”œÃ­n aparcados en lo que luego serâ”œÃ­ denominado "Calle Violante de Hungrâ”œÂ¡a", y en el enorme descampado de primer tâ”œÂ®rmino se edificarâ”œÃ­ el municipal equipamiento deportivo conocido como "El Huevo", por su oval diseâ”œâ–’o. El enorme bloque de viviendas de la derecha anuncia la cercana presencia del polâ”œÂ¡gono Romareda. Detrâ”œÃ­s de â”œÂ®l, la nueva calle de Asâ”œÂ¡n y Palacios, continuaciâ”œâ”‚n de la "vieja" Francisco de Borja.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.63981300, -0.90404300, '0101000020E6100000F3AFE595EBEDECBF1F477364E5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15279998311.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15279998311.webp', 'https://www.flickr.com/photos/zaragozaantigua/15279998311/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22465, 'Huerva 1968', 'Imagen capturada desde el cauce al aire del Huerva, justo antes de la gran curva que lo conduce al puente de San Josâ”œÂ®, aguas abajo, con parte del tramo pendiente de recubrimiento que, desde el fondo, se iba a acometer poco despuâ”œÂ®s. A la izquierda, conjunciâ”œâ”‚n visual del antiguo entorno del paseo de los Plâ”œÃ­tanos, con las industriosas construcciones de primer tâ”œÂ®rmino (harinera de Marcos Samper), y los grandes bloques emergentes, detrâ”œÃ­s, recayentes a la calle de Leon XIII nâ”¬â•‘ 1, 3 y 5. En el centro, al fondo, las traseras de la iglesia parroquial de Santa Engracia, y la pasarela peatonal que conectaba ambas mâ”œÃ­rgenes fluviales. A la derecha, muro perimetral y â”œÃ­rboles del colegio del Sagrado Corazâ”œâ”‚n del paseo de la Mina. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32749892084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32749892084.webp', 'https://www.flickr.com/photos/zaragozaantigua/32749892084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22718, 'Parque Miraflores 1979', 'Urbanizaciâ”œâ”‚n Parque de Miraflores desde la calle de Uncastillo, con el colegio Miraflores a la izquierda. Algunos bloques estâ”œÃ­n en construcciâ”œâ”‚n, y otros solares esperan ser urbanizados. El hexâ”œÃ­gono central serâ”œÃ­ ocupado despuâ”œÂ®s por la iglesia del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, sustituyendo a la advocaciâ”œâ”‚n de la plaza de San Pedro Nolasco, cerrada al culto. Al fondo, prolongaciâ”œâ”‚n de la avenida de Marina Moreno, ya redenominada de Cesâ”œÃ­reo Alierta.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64105300, -0.87802800, '0101000020E6100000FC1C1F2DCE18ECBF580053060ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30136070683.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30136070683.webp', 'https://www.flickr.com/photos/zaragozaantigua/30136070683/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22784, 'P.â”¬â•‘ de Marina Moreno 1979', 'Imagen capturada en el Polâ”œÂ¡gono 12 del barrio de San Josâ”œÂ®, una interesante zona de actuaciâ”œâ”‚n urbanâ”œÂ¡stica delimitada por la prolongaciâ”œâ”‚n del paseo de Marina Moreno, la calle de Miguel Servet, la avenida de San Josâ”œÂ® y el camino de las Torres que fue iniciada por el sector inmobiliario antes de que estuviera redactado el Plan Parcial que rigiera su ordenaciâ”œâ”‚n. Este Polâ”œÂ¡gono formaba parte del Plan General de Ordenaciâ”œâ”‚n Urbana del aâ”œâ–’o 1969. El Polâ”œÂ¡gono fue cogiendo forma al ritmo que marcaban los emprendedores privados sin previsiâ”œâ”‚n de equipamientos escolares, deportivos ni sanitarios, y las zonas verdes quedaron constreâ”œâ–’idas en la zona interior de las densas manzanas de bloques, a modo de los antiguos patios o corralas comunes. Este modelo de urbanismo a la carta supuso, ademâ”œÃ­s, el exponencial crecimiento de la circulaciâ”œâ”‚n automovilâ”œÂ¡stica en la zona. En la imagen, vista parcial del sector del Polâ”œÂ¡gono 12 entre la prolongaciâ”œâ”‚n del paseo de Marina Moreno (izquierda), el camino de las Torres (tras los modernos bloques del nâ”¬â•‘ 15 de Marina Moreno y el 27-29 de ese camino) y la calle de Lorenzo Pardo (derecha). En primer plano, solar habilitado como provisional aparcamiento en superficie donde aâ”œâ–’os despuâ”œÂ®s se levantarâ”œÂ¡a el edificio Los Arcos de CIUVASA. Fuente visual: Andalâ”œÃ­n, periâ”œâ”‚dico semanal aragonâ”œÂ®s, 1979.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.64431300, -0.87615800, '0101000020E6100000DE1E84807C09ECBF9EB12FD978D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38399599026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38399599026.webp', 'https://www.flickr.com/photos/zaragozaantigua/38399599026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22803, 'Polâ”œÂ¡gono Miraflores 1975', 'Imagen capturada en el Polâ”œÂ¡gono Miraflores durante el montaje de algunas de las atracciones que conformaban el recinto ferial habilitado durante las Fiestas del Pilar en esta zona, antes de su urbanizaciâ”œâ”‚n. Al fondo, muro perimetral tras el que destaca el volumen del colegio de los Agustinos y la parroquia de Santa Rita de Casia. A continuaciâ”œâ”‚n, bloques de viviendas del camino de las Torres, la torre que culminaba el moderno convento de la Congregaciâ”œâ”‚n de las Hermanas Oblatas del Santâ”œÂ¡simo Redentor, en la chaflanera esquina de la plaza del doctor Albert Schweitzer, y la chimenea de la fâ”œÃ­brica textil Lanera Aragonesa junto a la acequia de las Adulas del Huerva, o de San Josâ”œÂ®.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64120000, -0.87789700, '0101000020E610000059350873BB17ECBFFC1873D712D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48099409518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48099409518.webp', 'https://www.flickr.com/photos/zaragozaantigua/48099409518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22897, 'C.â”¬â•‘ de las Torres 1983', 'El camino de las Torres, en una escena nevada de su confluencia con la avenida de Cesâ”œÃ­reo Alierta, al fondo, con el telâ”œâ”‚n de sus grandes bloques del lado de los pares en el tramo hasta la calle de San Vicente Mâ”œÃ­rtir. A la izquierda e inmediato, tramo al aire de la acequia de San Josâ”œÂ®, y arqueolâ”œâ”‚gica vista del viejo y unidireccional camino de las Torres. A la derecha, la antigua fâ”œÃ­brica de Gas, durante el proceso de su derribo, donde destaca un cartel indicador de la empresa.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64568800, -0.87693400, '0101000020E6100000CD0358E4D70FECBFB7B585E7A5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20563238384.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20563238384.webp', 'https://www.flickr.com/photos/zaragozaantigua/20563238384/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22898, 'Cesâ”œÃ­reo Alierta 1983', 'Vista nevada de la avenida de Cesâ”œÃ­reo Alierta en una imagen capturada en altura desde el inmueble del nâ”¬â•‘ 15 del camino de las Torres. Inmediatas, dependencias de la fâ”œÃ­brica de Gas. A la derecha, torre y pabellones del colegio Sagrado Corazâ”œâ”‚n del paseo de la Mina, tras el râ”œÂ¡o Huerva. El gran solar de primer tâ”œÂ®rmino serâ”œÃ­ urbanizado luego con edificaciones residenciales, hoteleras, comerciales y trazado urbano, ademâ”œÃ­s del IES Medina Albaida. Al fondo, la mole del edificio central de Ibercaja.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64568800, -0.87693400, '0101000020E6100000CD0358E4D70FECBFB7B585E7A5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20565824553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20565824553.webp', 'https://www.flickr.com/photos/zaragozaantigua/20565824553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22964, 'Av. de Cesâ”œÃ­reo Alierta 1985', 'Imagen capturada en el primer tramo de los impares de la avenida de Cesâ”œÃ­reo Alierta y a espaldas del camino de las Torres. Esta foto, centrada originalmente en el asunto de uno de los anunciantes publicitarios de la derecha, nos da pie para traspasar figuradamente el muro perimetral que soporta los cartelones. Tras este muro se encontraba en situaciâ”œâ”‚n de barbecho expectante el enorme solar de la antigua huerta de la fâ”œÃ­brica de harinas de Solsona, que hacia el fondo continuaba donde esta empresa tuvo los edificios fabriles en una ubicaciâ”œâ”‚n junto al cauce del râ”œÂ¡o Huerva. Hacia la derecha y fuera de cuadro quedaba tambiâ”œÂ®n el vecino solar de la antigua Torre de Baselga y sus recordadas piscinas, seguido a continuaciâ”œâ”‚n por el solar que ocupara la Fâ”œÃ­brica de Gas de Zaragoza S.A. En primer tâ”œÂ®rmino, marquesina correspondiente a la parada "Av. Cesâ”œÃ­reo Alierta- Cn. Torres" de la lâ”œÂ¡nea 25 de autobâ”œâ•‘s "Bâ”¬â•‘ de La Cartuja-Miralbueno" de los Transportes Urbanos de Zaragoza, S.A. Unos aâ”œâ–’os mâ”œÃ­s tarde comenzarâ”œÂ¡a el proceso de urbanizaciâ”œâ”‚n de esta zona, con la construcciâ”œâ”‚n de varios modernos inmuebles de uso residencial, comercial, recreativo, hotelero, ministerial y educativo pâ”œâ•‘blico, una zona verde, ademâ”œÃ­s del tendido de un nuevo puente sobre el râ”œÂ¡o Huerva que supondrâ”œÂ¡a la apertura de una nueva calle denominada de Josâ”œÂ® Luis Pomarâ”œâ”‚n que comunica desde entonces el paseo de la Mina y el camino de las Torres.', 1985, 1985, 1985, 'Anos 80', 'CENTRO', 41.64550800, -0.87790700, '0101000020E61000003CBEBD6BD017ECBF37A79201A0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53261657282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53261657282.webp', 'https://www.flickr.com/photos/zaragozaantigua/53261657282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23067, 'Plaza de los Sitios 1997', 'Imagen capturada en el interior del Museo de Zaragoza durante la clausura de la exposiciâ”œâ”‚n "Permanencia de la memoria. Cartones para tapiz y dibujos de Goya" con que se dio por clausurado el denominado "Aâ”œâ–’o de Goya" que en 1996 y 1997 conmemorâ”œâ”‚ el aniversario 250 del nacimiento del pintor Francisco Goya. Para tal ocasiâ”œâ”‚n Zaragoza recibiâ”œâ”‚ la visita de Fabiola de Mora y Aragâ”œâ”‚n, aristâ”œâ”‚crata madrileâ”œâ–’a y reina consorte de los belgas tras su boda en 1960 con el rey Balduino de ese paâ”œÂ¡s. Asâ”œÂ¡, la fotografâ”œÂ¡a se centra en esta ilustre invitada flanqueada por altos representantes institucionales de la Espaâ”œâ–’a, el Aragâ”œâ”‚n y la Zaragoza de la â”œÂ®poca: a la derecha, Santiago Lanzuela Marina, presidente del Gobierno de Aragâ”œâ”‚n junto a su esposa Magdalena Gâ”œÃ­rate y Luis Antonio Rosel Onde, delegado del Gobierno en Aragâ”œâ”‚n. A la izquierda, Francisco â”œÃ¼lvarez Cascos, vicepresidente primero del Gobierno de Espaâ”œâ–’a, seguido por su segunda esposa Gema Ruiz; Luisa Fernanda Rudi â”œÃœbeda, alcaldesa de Zaragoza y Vicente Bielza de Ory, consejero de Educaciâ”œâ”‚n y Cultura del Gobierno de Aragâ”œâ”‚n. Tras el grupo y de telâ”œâ”‚n de fondo, el tapiz de Goya titulado "La boda", prestado por la Casa Real de Bâ”œÂ®lgica para formar parte de la referida exposiciâ”œâ”‚n. Este tapiz fue regalado en 1865 por la reina Isabel II de Espaâ”œâ–’a al nuevo rey de los belgas Leopoldo II con motivo de su coronaciâ”œâ”‚n, que aâ”œâ–’os despuâ”œÂ®s se coronarâ”œÂ¡a de pleno derecho como el genocida "carnicero del Congo".', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64820800, -0.87860500, '0101000020E61000003D44A33B881DECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54867683871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54867683871.webp', 'https://www.flickr.com/photos/zaragozaantigua/54867683871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23260, 'Camino de las Torres 1897', 'Imagen promocional de la que comenzâ”œâ”‚ siendo fâ”œÃ­brica de corsâ”œÂ®s de Pilar Lana en el camino de las Torres nâ”¬â•‘ 191, ya como fâ”œÃ­brica de chocolates, cafâ”œÂ®s y tâ”œÂ®s, aquâ”œÂ¡ ubicada durante un breve lapso de tiempo (1897-1901), antes de trasladarse a la calle del Cinco de Marzo, primero, y luego a la antigua huerta de Santa Engracia. Destaca el acceso a travâ”œÂ®s de un paso que salva la caudalosa acequia de las Adulas, del Penal, o de San Josâ”œÂ®, en su trâ”œÃ­nsito hacia Miguel Servet (por la izquierda). A la derecha, la caseta que derivaba para la fâ”œÃ­brica una parte del caudal de la acequia, y de la que salâ”œÂ¡a un riego con agua sobrante hacia la huerta de Miraflores. Fuente visual: www.todocoleccion.net/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64430500, -0.87808900, '0101000020E610000067463F1A4E19ECBF1CD3139678D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30562832100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30562832100.webp', 'https://www.flickr.com/photos/zaragozaantigua/30562832100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23268, 'Râ”œÂ¡o Huerva 1808', '"Baterâ”œÂ¡a de Santa Engracia: arruinada el 4 de Agosto de 1808". Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. La baterâ”œÂ¡a de Santa Engracia fue situada en las proximidades del convento e iglesia del mismo nombre, apoyada drectamente en el pretil del râ”œÂ¡o Huerva cuyo cauce al natural ejercâ”œÂ¡a de natural trinchera defensiva. En la otra ribera, mâ”œÃ­s elevada, merodean los soldados franceses. A la derecha, quedaba el puente de Santa Engracia, pronto destruido. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64702400, -0.87760500, '0101000020E610000068CBB9145715ECBF12DDB3AED1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15244837956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15244837956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15244837956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24087, 'Av. de Cesâ”œÃ­reo Alierta 1984', 'Imagen capturada junto a la entrada de "El Urbano", pabellâ”œâ”‚n habilitado durante las fiestas del Pilar por las peâ”œâ–’as Forca y El Rebullo en la vâ”œÂ¡a pâ”œâ•‘blica del paso a desnivel sito en la avenida de Cesâ”œÃ­reo Alierta bajo el camino de las Torres. Aunque ese mismo aâ”œâ–’o se habâ”œÂ¡a constituido la federaciâ”œâ”‚n Interpeâ”œâ–’as de Zaragoza, en la ciudad todavâ”œÂ¡a podâ”œÂ¡an encontrarse diversos espacios festivos impulsados por las peâ”œâ–’as, como el pabellâ”œâ”‚n de la avenida de San Josâ”œÂ®, de Interpeâ”œâ–’as, y este mismo. La concesiâ”œâ”‚n del uso del suelo en vâ”œÂ¡a pâ”œâ•‘blica comenzâ”œâ”‚ pues casi al principio de la segunda legislatura de la Corporaciâ”œâ”‚n encabezada por Ramâ”œâ”‚n Sainz de Varanda, si bien ya en 1986 su sucesor Antonio Gonzâ”œÃ­lez Triviâ”œâ–’o se mostrâ”œâ”‚ partidario de no autorizar tal ocupaciâ”œâ”‚n, "pues ocasiona colapsos de trâ”œÃ­fico en los paseos de la Independencia y de la Constituciâ”œâ”‚n". Fuente visual: exposiciâ”œâ”‚n Ã”Ã‡Ã–Zaragoza y las fiestas del PilarÃ”Ã‡Ã–.', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64455400, -0.87738100, '0101000020E61000008237A4518113ECBFC440D7BE80D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44168636594.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44168636594.webp', 'https://www.flickr.com/photos/zaragozaantigua/44168636594/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24132, 'Edificio de los Museos 1908', 'Imagen capturada durante el proceso de construcciâ”œâ”‚n del nuevo edificio de los Museos, proyectado por Ricardo Magdalena y Julio Bravo como parte constitutiva del complejo de la Expo de 1908, ubicada en los antiguos terrenos de la huerta de Santa Engracia. Este patio articula el espacio construido, en formas regionalistas, neomedievales, eclâ”œÂ®cticas. No deja de ser curioso este fenâ”œâ”‚meno local consistente en construir nuevos edificios en formas y estilos propios de los palacios del renacimiento y barroco, mientras en paralelo se dejaban caer, o se derribaban directamente, los autâ”œÂ®nticos palacios facturados en esos estilos. Este edificio sobreviviâ”œâ”‚ a los fastos expositivos, y desde entonces ha sido objeto de modificaciones muy importantes. En la actualidad alberga al Museo de Zaragoza. Fuente visual: Guâ”œÂ¡a del Museo de Zaragoza, DGA, 2003', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64824000, -0.87860500, '0101000020E61000003D44A33B881DECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18566518133.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18566518133.webp', 'https://www.flickr.com/photos/zaragozaantigua/18566518133/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24141, 'La Caridad 1907', 'Imagen obtenida a finales de 1907 durante la construcciâ”œâ”‚n del edificio denominado "La Caridad", que como parte integrante de los temporales pabellones de la Expo de 1908, ejercitarâ”œÃ­ de "Palacio de Industrias". La captura se ha realizado desde la actual calle de Josâ”œÂ® Canalejas, entonces desprovista de otras edificaciones. A la izquierda, tambiâ”œÂ®n en construcciâ”œâ”‚n, "El Palacio de los Museos". Al fondo, entre ambos edificios, mâ”œÃ­s andamios donde se estâ”œÃ­ levantando el edificio de "Las Escuelas", luego Escuela de Artes y Oficios. A la derecha, alameda del Paseo de la Mina. La imagen incluye un interesante apunte del proceso constructivo de la â”œÂ®poca: los regulares y pequeâ”œâ–’os "agujeros" de la fachada del edificio son los puntos de apoyo de los andamios de obra, que luego habrâ”œÃ­ que cerrar. Fuente visual: Foto Escolâ”œÃ­, para la revista "Mercurio".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64787600, -0.87832500, '0101000020E61000005E4BC8073D1BECBF80EECB99EDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20208715271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20208715271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20208715271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24146, 'Edificio &quot;Museos&quot; 1908', 'Imagen al final de la construcciâ”œâ”‚n del edificio destinado a "Museos" durante la Exposiciâ”œâ”‚n Hispano-Francesa de 1908, proyecto de Ricardo Magdalena, y Julio Bravo. Se trata del lateral izquierdo del edificio, en la parte final de la prolongada calle de Costa, que aâ”œâ–’os mâ”œÃ­s tarde serâ”œÂ¡a redenominada "Josâ”œÂ® Canalejas". Fuente visual: "Arquitectura y Construcciâ”œâ”‚n" (Barcelona).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64796100, -0.87860400, '0101000020E61000002750C422861DECBFAF0AD462F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22016715843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22016715843.webp', 'https://www.flickr.com/photos/zaragozaantigua/22016715843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24147, 'Edificio &quot;Museos&quot; 1908', 'Imagen al final de la construcciâ”œâ”‚n del edificio destinado a "Museos" durante la Exposiciâ”œâ”‚n Hispano-Francesa de 1908, proyecto de Ricardo Magdalena, y Julio Bravo. Fuente visual: "Arquitectura y Construcciâ”œâ”‚n" (Barcelona).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64824000, -0.87860500, '0101000020E61000003D44A33B881DECBFC2FA3F87F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22611099046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22611099046.webp', 'https://www.flickr.com/photos/zaragozaantigua/22611099046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24151, 'Edificio de los Museos 1908', 'Imagen de un grupo de personas disfrazadas de soldados de la Guerra de Independencia 1808-1814 posan en el patio del Edificio de los Museos de la antigua Huerta de Santa Engracia. "Para hacer la fotografâ”œÂ¡a en colores segâ”œâ•‘n el nuevo procedimiento Lumiere, fueron los soldados de 1808 agrupados en el gran Patio del Palacio del Arte Antiguo". Fuente visual: lâ”œÃ­mina en color reproducida por la Sociedad Lionesa de Fotocromograbado Hemmerlâ”œÂ® de Lyon, con clichâ”œÂ® de M. Emile Bertaux, obtenido con placa autocroma de los Sres. Lumiâ”œÂ¿re hermanos, en "Exposiciâ”œâ”‚n Retrospectiva de Arte.-1908 Organizada bajo los auspicios del Excelentâ”œÂ¡simo Sr. Arzobispo de Zaragoza. [Real Junta del Centenario de los Sitios de 1808-1809] -L''Exposition Retrospective d''Art - 1908. Organisee sous les auspices de S. G. l''Archiveque de Saragosse. [Commission Royale du Centenaire des Sieges de 1808-1809]". Tipografia La Editorial (Zaragoza)-Librerâ”œÂ¡a Central de Bellas Artes (Parâ”œÂ¡s), 1910.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64823000, -0.87861700, '0101000020E61000004EB51666A11DECBF9E245D33F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26756038775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26756038775.webp', 'https://www.flickr.com/photos/zaragozaantigua/26756038775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24156, 'Prâ”œâ”‚rroga Expo 1908', 'Imagen capturada en el interior del recinto de la Exposiciâ”œâ”‚n Hispano Francesa de 1908, con un coral posado de pardales ante el emblemâ”œÃ­tico pabellâ”œâ”‚n de Alimentaciâ”œâ”‚n. La clausura de esta muestra estaba prevista inicialmente a finales de octubre, pero la afluencia de pâ”œâ•‘blico prorrogâ”œâ”‚ el cierre hasta el mes de diciembre. Esta imagen se podrâ”œÂ¡a corresponder con esa etapa, tanto por las mantas y ropas de abrigo generalizadas, como porque ya es posible ver, al fondo, las alegorâ”œÂ¡as de la escultura, pintura y arquitectura, talladas por Carlos Palao como ornato de la fachada principal del Palacio de los Museos, y colocadas con un cierto retraso respecto de la fecha prevista. Fuente visual: Foto Estudio Coyne, AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64839400, -0.87966600, '0101000020E61000007DE6AC4F3926ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31562618871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31562618871.webp', 'https://www.flickr.com/photos/zaragozaantigua/31562618871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24713, 'Barriada de Escoriaza 1991', 'Imagen capturada en las traseras de la barriada "Vizconde de Escoriaza" construida en 1953 para trabajadores de la empresa Los tranvâ”œÂ¡as de Zaragoza S.A., y con ingreso principal por la calle de Fray Luis Urbano. En primer tâ”œÂ®rmino, riego derivado de la acequia de San Josâ”œÂ® que, tras pasar soterrado bajo el grupo de viviendas vuelve a salir al aire bajo un puentecillo que salva su paso por lo que, aunque tâ”œÂ®cnicamente ya era el â”œâ•‘ltimo tramo de la calle de San Adriâ”œÃ­n de Sasabe, a efectos prâ”œÃ­cticos todavâ”œÂ¡a no lo parecâ”œÂ¡a.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64860800, -0.85766300, '0101000020E6100000EBA7FFACF971EBBF45F6419605D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450638752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450638752.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450638752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24166, 'P.â”¬â•‘ de la Mina 1907', 'Tardo-octubrina magen capturada durante las obras de construcciâ”œâ”‚n del edificio "La Caridad", concebido como segundo pabellâ”œâ”‚n permanente de la exposiciâ”œâ”‚n Hispano-Francesa de 1908, asâ”œÂ¡ denominado porque fue ideado para albergar luego la instituciâ”œâ”‚n benâ”œÂ®fica asâ”œÂ¡ denominada, fundada para evitar la mendicidad callejera. Fue proyectado por los arquitectos Luis de la Figuera Lezcano y Josâ”œÂ® de Yarza Echenique, si bien al entregar cada uno su propio proyecto de edificio se encargâ”œâ”‚ de refundirlos y darles â”œâ•‘nica forma el arquitecto municipal Ricardo Magdalena Tabuenca. Presupuestado en unas 300.000 pesetas, fue entregado a la muestra en abril de 1908. En la imagen, momento constructivo de este pabellâ”œâ”‚n en una vista tomada desde el paseo de Ronda o de la Mina.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64775100, -0.87786500, '0101000020E610000081B229577817ECBFC4793881E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54160569916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54160569916.webp', 'https://www.flickr.com/photos/zaragozaantigua/54160569916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24244, 'Josâ”œÂ® Galiay c.1950', 'Imagen de Josâ”œÂ® Galiay Saraâ”œâ–’ana (1880-1952), posiblemente en su despacho de director del Museo Provincial de Zaragoza. En su destacada faceta fotogrâ”œÃ­fica, muy practicada en su etapa de comisario de excavaciones arqueolâ”œâ”‚gicas y de zona del Patrimonio Artâ”œÂ¡stico, destaca su constituciâ”œâ”‚n del visual "Fichero de Arte Aragonâ”œÂ®s", con numerosas imâ”œÃ­genes de la Zaragoza de la primera mitad del siglo XX. Fuente visual: Archivo Fotogrâ”œÃ­fico Josâ”œÂ® Galiay-AHPZ', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64823000, -0.87861700, '0101000020E61000004EB51666A11DECBF9E245D33F9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450016294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450016294.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450016294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
