INSERT INTO public.photos VALUES (24278, 'Quiosco de la Mâ”œâ•‘sica 1908', '1908. Imagen del "Quiosco de mâ”œâ•‘sica" en el entorno de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908, en la Huerta de Santa Engracia. El Quiosco se encuentra entre el Pabellâ”œâ”‚n de la Alimentaciâ”œâ”‚n (derecha), y el "Pabellâ”œâ”‚n Francâ”œÂ®s". Al fondo, viviendas de la cercana calle San Miguel. El Quiosco de primer plano es de otro tipo de musicalidad, mâ”œÃ­s lâ”œÂ¡quida. El musical Quiosco, mâ”œÃ­s que musical, serâ”œÃ­ viajero, muy viajero: en 1912 fue trasladado al Paseo de la Independencia; en 1924 volviâ”œâ”‚ a su ubicaciâ”œâ”‚n en esta plaza, denominada de Castelar; en los aâ”œâ–’os 60 fue de nuevo trasladado, en esta ocasiâ”œâ”‚n al Parque Primo de Rivera. Allâ”œÂ¡ sigue, aunque ahora ha sido redenominado Parque Grande Josâ”œÂ® Antonio Labordeta.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64840000, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14981876831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14981876831.webp', 'https://www.flickr.com/photos/zaragozaantigua/14981876831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22046, 'Trolebâ”œâ•‘s del Terminillo 1951', 'Colecciâ”œâ”‚n Mariano Rodrâ”œÂ¡guez Trolebâ”œâ•‘s de la lâ”œÂ¡nea Terminillo, con el volante a la derecha por ser de fabricaciâ”œâ”‚n britâ”œÃ­nica, a su paso por la comisarâ”œÂ¡a de la avenida Valencia de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64520600, -0.89987400, '0101000020E61000009BA9108FC4CBECBF6C97361C96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14795594968.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14795594968.webp', 'https://www.flickr.com/photos/zaragozaantigua/14795594968/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24281, 'La Caridad c.1930', 'Reparto del bono semanal a los mendigos de la ciudad, por parte de la instituciâ”œâ”‚n denominada La Caridad (calle Segismundo Moret, 4), en las traseras del Museo de Zaragoza, que se ve al fondo, antes de la actual plaza de Los Sitios. La Asociaciâ”œâ”‚n Benâ”œÂ®fica Ã”Ã‡Â£La CaridadÃ”Ã‡Ã˜ lleva desde enero de 1910 en un edificio que formâ”œâ”‚ parte de los pabellones de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. La presencia de guardia urbana (de uniforme, armados) y de funcionarios del Cuerpo (de paisano, desarmados) tiene que ver con la importante implicaciâ”œâ”‚n municipal del Ayuntamiento en el proyecto. Fuente visual: La Caridad, Centenaria. Sus primeros aâ”œâ–’os (1898-1910), Ayuntamiento de Zaragoza, 2000.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64832800, -0.87778100, '0101000020E61000000B9B012EC816ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15113536428.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15113536428.webp', 'https://www.flickr.com/photos/zaragozaantigua/15113536428/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24287, 'Pabellâ”œâ”‚n AHV 1908', 'Pabellâ”œâ”‚n particular de Altos Hornos de Vizcaya, con forma de horno de fundiciâ”œâ”‚n, en la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza en 1908. Se encontraba en las inmediaciones de la actual calle de Mefisto. Fuente visual: sestao.wordpress.com/2012/10/15/pabellon-de-ahv-en-la-exp... mostrada en www.facebook.com/photo.php?fbid=369314759892026&set=o...', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64789000, -0.87957500, '0101000020E610000068226C787A25ECBFE5B33C0FEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15491146509.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15491146509.webp', 'https://www.flickr.com/photos/zaragozaantigua/15491146509/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24288, 'Exposiciâ”œâ”‚n Hispano Francesa 1908', 'Vista del recinto de la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza en 1908. En primer plano, a la derecha, torre del Pabellâ”œâ”‚n Mariano desde la altura del vecino Pabellâ”œâ”‚n particular de Altos Hornos de Vizcaya. A al izquierda, otros pabellones particulares, y el gran Pabellâ”œâ”‚n de Maquinaria. Al fondo, la vieja ciudad. Fuente visual: "Vista general de la Exposiciâ”œâ”‚n Hispano-Francesa", fotografâ”œÂ¡a de Ignacio Coynâ”œÂ®, en "Zaragoza artâ”œÂ¡stica â”œÂ® industrial. â”œÃ¼lbum de la Exposiciâ”œâ”‚n", 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64815500, -0.87937500, '0101000020E6100000A4703D0AD723ECBF94DE37BEF6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15495429258.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15495429258.webp', 'https://www.flickr.com/photos/zaragozaantigua/15495429258/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
