INSERT INTO public.photos VALUES (24291, 'Marina Moreno 1968', 'Una maâ”œâ–’ana de niebla, el seâ”œâ–’or Câ”œÂ®sar Garcia Jarque estaba por la "Avenida" Marina Moreno, donde arranca el paseo de la Mina, y se puso a hacer una foto a una pareja de currelas cruzando por el lugar mâ”œÃ­s directo entre dos puntos, que suele ser una recta. Detrâ”œÃ­s del tablâ”œâ”‚n, el colegio de los Hermanos del Sagrado Corazâ”œâ”‚n. Detrâ”œÃ­s del colegio, el Huerva vuelve a salir al aire tras su paseo subterrâ”œÃ­neo por la ciudad, y se topa con la mole poligonal del depâ”œâ”‚sito del "Gas". Tâ”œÂ¡midas sombras indican que la niebla se estâ”œÃ­ disipando. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64715700, -0.87952800, '0101000020E61000003B527DE71725ECBF5130630AD6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15730364527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15730364527.webp', 'https://www.flickr.com/photos/zaragozaantigua/15730364527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24294, 'Marina Moreno 1975', 'Archivo Municipal. Gerardo Sancho Ramo. Febrero 1975. Imagen de las obras de la prolongaciâ”œâ”‚n del Paseo de Marina Moreno por debajo del Camino de las Torres. La prolongaciâ”œâ”‚n de Marina Moreno se estaba realizando, a la izquierda de esta imagen, mediante un tâ”œâ•‘nel carretero que pretendâ”œÂ¡a ser una gran autopista de salida y entrada al cogollo de la ciudad, ademâ”œÃ­s de revitalizar, de paso, a los barrios del sureste, una cancioncilla esta de la revitalizaciâ”œâ”‚n del Sureste urbano que, cuarenta aâ”œâ–’os despuâ”œÂ®s, aâ”œâ•‘n tiene intâ”œÂ®rpretes en el consistorio. Al fondo, los edificios que seâ”œâ–’alan el comienzo del actual Paseo de la Mina. A la derecha, las traseras del antiguo edificio del colegio del Sagrado Corazâ”œâ”‚n, junto al Huerva.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64597100, -0.87840100, '0101000020E61000001EC2F869DC1BECBF0C957F2DAFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16063158866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16063158866.webp', 'https://www.flickr.com/photos/zaragozaantigua/16063158866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
