INSERT INTO public.photos VALUES (24324, 'Marina Moreno 1978', 'Imagen capturada desde cierta altura del paseo de Marina Moreno, con interesante visual, al fondo, del camino de las Torres, con el edificado y moderno tramo entre las calles de Gonzalo de Berceo, a la izquierda, y Manuel Lorenzo Pardo, a la derecha, en el que destacan los huecos de los nâ”œâ•‘meros 15 (izquierda), y 25 (centro). Justo enfrente de todos ellos, el contraste con algunas de las antiguas instalaciones de la fâ”œÃ­brica del "Gas", y el enorme solar esquinero con Marina Moreno, e inmediato al cauce del Huerva. A la izquierda, asoma la emergente estructura del moderno edificio del nâ”¬â•‘ 16-18 de camino de las Torres. En el andador central del paseo, la antigua estatuilla del "Buen Pastor" que originalmente estuviera en el patio de entrada del Matadero municipal. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64689500, -0.87932300, '0101000020E610000005DCF3FC6923ECBF14799274CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32665703006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32665703006.webp', 'https://www.flickr.com/photos/zaragozaantigua/32665703006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
